    viewport === "desktop" ? 72 : 48
  );

  if (viewport === "desktop") {
    expect(new Set(boxes.slice(0, 6).map((box) => box.x)).size).toBeGreaterThanOrEqual(3);
  } else {
    expect(Math.max(...boxes.map((box) => box.x)) - Math.min(...boxes.map((box) => box.x))).toBeLessThanOrEqual(2);
